mapper.select:
select id, location, ip, flag, mark, cameras, volume, is_warning, name, status
from yn_siren

    and location like concat('%', #{location}, '%')
    and ip like concat('%', #{ip}, '%')
    and flag = #{flag}
    and is_warning = #{isWarning}
    and name like concat('%', #{name}, '%')
    and status = #{status}

order by id desc
